const { Client } = require('pg');
const axios = require('axios');

// Load environment variables from .env.test
require('dotenv').config({ path: '.env.test' });

async function testDatabaseConnection() {
    const client = new Client({
        connectionString: process.env.DATABASE_URL,
    });
    try {
        await client.connect();
        console.log('Database connection successful.');
    } catch (error) {
        console.error('Database connection failed:', error);
    } finally {
        await client.end();
    }
}

async function testApiKey(apiKey, url) {
    try {
        const response = await axios.get(url, {
            headers: { 'Authorization': `Bearer ${apiKey}` }
        });
        console.log(`API key test successful for ${url}:`, response.data);
    } catch (error) {
        console.error(`API key test failed for ${url}:`, error.response ? error.response.data : error.message);
    }
}

async function runTests() {
    await testDatabaseConnection();
    await testApiKey(process.env.ANTHROPIC_API_KEY, 'https://api.anthropic.com/v1/health'); // Example endpoint
    await testApiKey(process.env.STRIPE_SECRET_KEY, 'https://api.stripe.com/v1/charges'); // Example endpoint
}

runTests();

