const { Client } = require('pg');
const axios = require('axios');

// Load environment variables from .env.test
require('dotenv').config({ path: '.env.test' });

async function checkDatabase() {
    const client = new Client({
        connectionString: process.env.DATABASE_URL,
    });
    try {
        await client.connect();
        console.log('Database connection successful.');
    } catch (error) {
        console.error('Database connection failed:', error);
    } finally {
        await client.end();
    }
}

async function checkApiKeys() {
    const apiChecks = [
        { url: 'https://api.anthropic.com/v1/health', key: process.env.ANTHROPIC_API_KEY },
        { url: 'https://api.stripe.com/v1/charges', key: process.env.STRIPE_SECRET_KEY },
    ];

    for (const { url, key } of apiChecks) {
        try {
            const response = await axios.get(url, {
                headers: { 'Authorization': `Bearer ${key}` }
            });
            console.log(`API check for ${url} successful:`, response.data);
        } catch (error) {
            console.error(`API check for ${url} failed:`, error.response ? error.response.data : error.message);
        }
    }
}

async function runChecks() {
    await checkDatabase();
    await checkApiKeys();
}

runChecks();

