    const apiKeys = {
        'Anthropic': process.env.ANTHROPIC_API_KEY,
        'Stripe': process.env.STRIPE_SECRET_KEY,
    };

    for (const [service, key] of Object.entries(apiKeys)) {
        try {
            const response = await axios.get(`https://api.${service.toLowerCase()}.com/v1/some-endpoint`, {
                headers: { 'Authorization': `Bearer ${key}` }
            });
            console.log(`${service} API key is valid. Response status: ${response.status}`);
        } catch (error) {
            console.error(`${service} API key is invalid or request failed:`, error.message);
        }
    }
}

async function main() {
    await checkDatabase();
    await checkApiKeys();
}

main();

